import java.io.*;
import org.owasp.esapi.ESAPI;

public class XSSSecureCode {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.println("Enter your name: ");
        String userName = reader.readLine();

        // Encode user input to prevent XSS
        String encodedUserName = ESAPI.encoder().encodeForHTML(userName);

        System.out.println("Hello, " + encodedUserName + "!");

        // The following line is now safe from XSS attacks
        System.out.println("<script>alert('XSS attack by " + encodedUserName + "');</script>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
